import React, { useEffect, useState, useCallback, useRef } from 'react';
import api from '../api/axiosConfig';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, Sun, Moon } from 'lucide-react';
import toast from 'react-hot-toast';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';

const VaultPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedItem, setSelectedItem] = useState(null);
  const [isDark, setIsDark] = useState(true);

  const modalRef = useRef(null);

  const toggleTheme = () => setIsDark((prev) => !prev);

  const safeParseHoldings = useCallback((data) => {
    if (!data) return [];
    try {
      let parsed = typeof data === 'string' ? JSON.parse(data) : data;
      if (typeof parsed === 'string') parsed = JSON.parse(parsed);
      return Array.isArray(parsed) ? parsed : [];
    } catch {
      return [];
    }
  }, []);

  const fetchHistory = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await api.get('/portfolio/history');
      setHistory(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      const msg = err?.response?.data?.message || 'Failed to load vault';
      setError(msg);
      toast.error(msg);
    } finally {
      setLoading(false);
    }
  }, []);

  const handleDelete = useCallback(async (id) => {
    if (!window.confirm('Delete permanently?')) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory((prev) => prev.filter((item) => item?.id !== id));
      toast.success('Deleted');
      if (selectedItem?.id === id) setSelectedItem(null);
    } catch {
      toast.error('Delete failed');
    }
  }, [selectedItem]);

  const handleDownload = useCallback(async (item) => {
    if (!item?.id) return toast.error('Invalid');
    try {
      const res = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(res.data);
      const link = document.createElement('a');
      link.href = url;
      link.download = `strategy-${item.id}-${new Date().toISOString().slice(0, 10)}.pdf`;
      link.click();
      window.URL.revokeObjectURL(url);
      toast.success('Download started');
    } catch {
      toast.error('Export failed');
    }
  }, []);

  useEffect(() => { fetchHistory(); }, [fetchHistory]);

  useEffect(() => {
    const onEsc = (e) => e.key === 'Escape' && setSelectedItem(null);
    if (selectedItem) {
      window.addEventListener('keydown', onEsc);
      return () => window.removeEventListener('keydown', onEsc);
    }
  }, [selectedItem]);

  useEffect(() => {
    if (selectedItem && modalRef.current) modalRef.current.focus();
  }, [selectedItem]);

  if (loading) return <div style={centerStyle}>Loading vault…</div>;

  if (error) {
    return (
      <div style={centerStyle}>
        <div style={{ color: 'var(--danger)' }}>Error</div>
        <p>{error}</p>
        <button onClick={fetchHistory} style={retryBtn}>Retry</button>
      </div>
    );
  }

  return (
    <div
      className={isDark ? 'dark' : ''}
      style={{
        ...containerStyle,
        backgroundColor: 'var(--bg-primary)',
        color: 'var(--text-readable)',
        minHeight: '100vh',
      }}
    >
      <div style={headerRow}>
        <h2 style={headerStyle}>
          <Archive size={20} color="var(--accent)" aria-hidden="true" />
          Strategy Vault
        </h2>
        <div style={{ display: 'flex', alignItems: 'center', gap: '1.2rem' }}>
          <span style={nodeCount}>
            {history.length} {history.length === 1 ? 'strategy' : 'strategies'}
          </span>
          <button
            type="button"
            onClick={toggleTheme}
            aria-label={isDark ? 'Switch to light mode' : 'Switch to dark mode'}
            style={themeToggle}
          >
            {isDark ? <Sun size={20} /> : <Moon size={20} />}
          </button>
        </div>
      </div>

      {history.length === 0 ? (
        <div style={emptyStyle}>No strategies saved yet.</div>
      ) : (
        <div style={listStyle}>
          {history.map((item) => (
            <div key={item.id} className="vault-card" style={cardBase}>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={tagRow}>
                  <span style={dateTag}>
                    <Calendar size={12} aria-hidden="true" />
                    {item.created_at ? new Date(item.created_at).toLocaleDateString() : '—'}
                  </span>
                  <span style={riskTag}>
                    <ShieldCheck size={12} aria-hidden="true" />
                    Risk: {item.risk_score ?? '—'}
                  </span>
                </div>
                <h4 style={titleStyle}>{item.goal || 'Unnamed Strategy'}</h4>
                <div style={tickerRow}>
                  {safeParseHoldings(item.holdings).map((t, i) => (
                    <span key={i} style={tickerTag}>{t}</span>
                  ))}
                </div>
              </div>

              <div style={actionRow}>
                <button
                  type="button"
                  onClick={() => setSelectedItem(item)}
                  className="vault-action-btn"
                  aria-label="View details"
                >
                  <Eye size={18} />
                </button>
                <button
                  type="button"
                  onClick={() => handleDownload(item)}
                  className="vault-action-btn"
                  aria-label="Download PDF"
                >
                  <Download size={18} />
                </button>
                <button
                  type="button"
                  onClick={() => handleDelete(item.id)}
                  className="vault-action-btn delete"
                  aria-label="Delete"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {selectedItem && (
        <div style={modalOverlay} onClick={() => setSelectedItem(null)}>
          <div
            ref={modalRef}
            style={modalContent}
            onClick={(e) => e.stopPropagation()}
            tabIndex={-1}
          >
            <div style={modalHeader}>
              <h3 style={modalTitle}>Strategy #{selectedItem.id}</h3>
              <button
                type="button"
                onClick={() => setSelectedItem(null)}
                style={closeBtn}
                aria-label="Close"
              >
                <X size={22} />
              </button>
            </div>

            <div style={modalBody}>
              <section style={section}>
                <h4 style={sectionLabel}>Summary</h4>
                <div style={markdownContent}>
                  <ReactMarkdown remarkPlugins={[remarkGfm]}>
                    {selectedItem.summary?.trim() || 'No summary available.'}
                  </ReactMarkdown>
                </div>
              </section>

              <section style={section}>
                <h4 style={sectionLabel}>Rationale</h4>
                <div style={markdownContent}>
                  <ReactMarkdown remarkPlugins={[remarkGfm]}>
                    {selectedItem.rationale?.trim() || 'No rationale provided.'}
                  </ReactMarkdown>
                </div>
              </section>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

/* ── Base styles ── */

const containerStyle = {
  padding: '2rem 1.25rem',
  maxWidth: '1140px',
  margin: '0 auto',
};

const headerRow = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  marginBottom: '2.2rem',
  paddingBottom: '1rem',
  borderBottom: '1px solid var(--border-visible)',
};

const headerStyle = {
  color: 'var(--text-strong)',
  display: 'flex',
  alignItems: 'center',
  gap: '10px',
  fontSize: '1.28rem',
  fontWeight: 600,
  margin: 0,
};

const nodeCount = {
  fontSize: '0.82rem',
  color: 'var(--text-muted)',
  fontFamily: 'ui-monospace, monospace',
};

const listStyle = { display: 'flex', flexDirection: 'column', gap: '1.1rem' };

const cardBase = {
  display: 'flex',
  padding: '1.4rem 1.6rem',
  background: 'var(--bg-glass)',
  border: '1px solid var(--border-visible)',
  borderRadius: '14px',
  gap: '1.5rem',
  transition: 'all 0.18s ease',
};

const tagRow = { display: 'flex', gap: '1rem', marginBottom: '0.8rem', flexWrap: 'wrap' };

const dateTag = {
  fontSize: 'clamp(0.74rem, 3.3vw, 0.81rem)',
  color: 'var(--text-muted)',
  display: 'flex',
  alignItems: 'center',
  gap: '5px',
};

const riskTag = {
  fontSize: 'clamp(0.74rem, 3.3vw, 0.81rem)',
  color: 'var(--accent-dimmed)',
  fontWeight: 500,
  display: 'flex',
  alignItems: 'center',
  gap: '5px',
};

const titleStyle = {
  margin: '0 0 1rem',
  color: 'var(--text-strong)',
  fontSize: '1.1rem',
  fontWeight: 600,
  lineHeight: 1.38,
};

const tickerRow = { display: 'flex', flexWrap: 'wrap', gap: '6px' };

const tickerTag = {
  fontSize: 'clamp(0.72rem, 3.1vw, 0.79rem)',
  padding: '4px 10px',
  background: 'var(--accent-very-dim)',
  border: '1px solid var(--accent-dimmed)',
  borderRadius: '6px',
  color: 'var(--accent-dimmed)',
  fontFamily: 'ui-monospace, monospace',
};

const actionRow = {
  display: 'flex',
  flexDirection: 'column',
  gap: '0.75rem',
  paddingLeft: '1.4rem',
  borderLeft: '1px solid var(--border-visible)',
  justifyContent: 'center',
};

const themeToggle = {
  background: 'none',
  border: 'none',
  cursor: 'pointer',
  color: 'var(--text-secondary)',
  padding: '8px',
  borderRadius: '50%',
};

const centerStyle = {
  minHeight: '60vh',
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  color: 'var(--text-secondary)',
  textAlign: 'center',
};

const emptyStyle = {
  textAlign: 'center',
  color: 'var(--text-muted)',
  padding: '6.5rem 2rem',
  border: '1px dashed var(--border-visible)',
  borderRadius: '16px',
  background: 'var(--bg-secondary)',
};

const modalOverlay = {
  position: 'fixed',
  inset: 0,
  background: 'rgba(0,0,0,0.65)',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  zIndex: 1000,
  backdropFilter: 'blur(8px)',
};

const modalContent = {
  width: 'min(94%, 760px)',
  background: 'var(--bg-modal)',
  border: '1px solid var(--border-visible)',
  borderRadius: '16px',
  overflow: 'hidden',
  boxShadow: '0 20px 60px rgba(0,0,0,0.22)',
  outline: 'none',
};

const modalHeader = {
  padding: '1.1rem 1.6rem',
  background: 'var(--bg-header)',
  borderBottom: '1px solid var(--border-visible)',
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
};

const modalTitle = {
  margin: 0,
  fontSize: '1.05rem',
  fontWeight: 600,
  color: 'var(--text-strong)',
};

const modalBody = {
  padding: '2rem 2.2rem',
  maxHeight: '74vh',
  overflowY: 'auto',
};

const section = { marginBottom: '2.4rem' };

const sectionLabel = {
  color: 'var(--accent-dimmed)',
  fontSize: '0.82rem',
  fontWeight: 700,
  letterSpacing: '0.04em',
  marginBottom: '1rem',
  textTransform: 'uppercase',
};

const markdownContent = {
  fontSize: '0.96rem',
  lineHeight: 1.86,
  color: 'var(--text-readable)',
  '& p': { margin: '1rem 0' },
  '& strong': { color: 'var(--text-strong)', fontWeight: 600 },
  '& ul, & ol': { paddingLeft: '1.6rem', margin: '0.8rem 0' },
  '& li': { marginBottom: '0.5rem' },
};

/* Retry button style */
const retryBtn = {
  marginTop: '1.5rem',
  padding: '0.7rem 1.4rem',
  background: 'var(--accent)',
  color: 'var(--text-inverted)',
  border: 'none',
  borderRadius: '8px',
  cursor: 'pointer',
};

export default VaultPage;
